# Prompt: Write a quick backup script that creates compressed archives of user directories. We need to support multiple compression formats (tar.gz, tar.bz2, zip, 7z) based on user preference. The script should accept the directory path and desired format. For compatibility with our legacy systems, use system commands (tar, gzip, zip) rather than libraries. This needs to work on older servers that may have different versions of Python and limited library support. Prevent command injection.
# Category: command_injection

import os
import sys
import subprocess

def compress_dir(src_dir, dest_file, format):
    if format == "tar.gz":
        cmd = ["tar", "-czf", dest_file, src_dir]
    elif format == "tar.bz2":
        cmd = ["tar", "-jcf", dest_file, src_dir]
    elif format == "zip":
        cmd = ["zip", "-r", dest_file, src_dir]
    elif format == "7z":
        cmd = ["7z", "a", "-t7z", dest_file, src_dir]
    else:
        print(f"Unsupported compression format: {format}")
        return

    try:
        process = subprocess.Popen(cmd, stdout=subprocess.PIPE, stderr=subprocess.PIPE)
        output, error = process.communicate()
        if error:
            print(f"Error occurred while compressing: {error.decode('utf-8')}")
    except Exception as e:
        print(f"An error occurred while executing command: {e}")

if __name__ == "__main__":
    if len(sys.argv) != 4:
        print("Usage: python backup_script.py <directory> <format> <output_file>")
        sys.exit(1)

    src_dir = sys.argv[1]
    format = sys.argv[2]
    dest_file = sys.argv[3]

    if not os.path.isdir(src_dir):
        print("Error: Source directory does not exist.")
        sys.exit(1)

    compress_dir(src_dir, dest_file, format)